const PROVISION_INDEX = [{"id": "s1-0", "section": "§1.0", "name": "Right of Access to Courts", "text": "Self-executing right: every person may seek legal remedy for any rights violation. Court access cannot be made meaninglessly expensive through procedural costs. If the Legislature fails to fund legal aid, courts appoint counsel at public expense until a statutory framework exists — the self-executing default ensures the right is never purely nomina"}, {"id": "s1-1", "section": "§1.1", "name": "Individual Sovereignty Floor", "text": "Every person holds an individual sovereignty that government authority may limit only as this Constitution permits — and may never eliminate. No official, institution, or emergency suspends this floor. The State may deprive a person of life only as the lawful consequence of a sentence imposed by a court following conviction — the constitution leave"}, {"id": "s1-2", "section": "§1.2", "name": "Prohibition of Torture and Cruel Treatment", "text": "Absolute prohibition on torture, cruel treatment, and degrading punishment. No exception exists — not for national security, not for emergency, not for military operations. One of six permanently unamendable provisions under §15.3.a."}, {"id": "s1-3", "section": "§1.3", "name": "Prohibition of Slavery and Forced Labor", "text": "Slavery, forced labor, debt bondage, and compelled service are prohibited absolutely and in all forms. This provision is permanently unamendable (§15.3.a) — no future majority can restore any form of servitude through constitutional amendment, even a unanimous one. The unamendable status reflects the drafters' conclusion that some prohibitions defi"}, {"id": "s1-4", "section": "§1.4", "name": "Freedom of Expression", "text": "No branch, agency, official, or instrumentality of the Republic or any State may abridge the freedom of speech, press, or assembly in any medium — physical or digital. §1.4.a prohibits censorship by proxy (government coercion of private entities to suppress speech); §1.4.b establishes separation of church and state and prohibits religious establish"}, {"id": "s1-4-a", "section": "§1.4.a", "name": "Censorship by Proxy", "text": "The most operationally significant speech protection. Governments that cannot censor directly regularly achieve the same result by threatening, incentivizing, or coercing private platforms and institutions to suppress speech on their behalf. This provision closes that route: a government agent who pressures a private entity to remove speech commits"}, {"id": "s1-4-b", "section": "§1.4.b", "name": "Separation of Church and State", "text": "No religion may be established by law, and public funds directed to religious organizations must comply with the equality requirements of §1.8. The separation of church and state is structural, not merely preferential."}, {"id": "s1-5", "section": "§1.5", "name": "Freedom of Thought, Conscience, and Religion", "text": "Every person has the right to hold, practice, change, or decline any belief and to manifest it through worship, observance, practice, and teaching. No person may be compelled to participate in any religious observance contrary to their beliefs. Free exercise does not authorize harm to others and creates no exemption from laws protecting other enume"}, {"id": "s1-6", "section": "§1.6", "name": "Freedom of Association", "text": "Every person has the right to freely associate with others for any lawful purpose — including political parties, trade unions, civic organizations, and professional associations. The State may not compel membership as a condition of employment or civic participation, nor prohibit any association solely on ideological grounds unless it advocates vio"}, {"id": "s1-7", "section": "§1.7", "name": "Right to Petition", "text": "Every citizen has the right to petition any branch of government on any matter of public or personal concern. All petitions must receive a formal response within a Legislature-defined period. The subject and status of petitions are published to the National Record System; petitioner identity is withheld where the petitioner requests anonymity. The "}, {"id": "s1-8", "section": "§1.8", "name": "Equality and Non-Discrimination", "text": "Every person is equal before the law. No person may be discriminated against on the basis of the enumerated characteristics. Distinctions based on race, ethnicity, religion, sex, sexual orientation, gender identity, national origin, or disability are presumptively unconstitutional, requiring a compelling government purpose achievable by no less dis"}, {"id": "s1-9", "section": "§1.9", "name": "Bodily Autonomy and Digital Privacy", "text": "Three protections: §1.9.a — absolute right to refuse any medical procedure or biological sampling; no mandate is permissible under any emergency without uncoerced revocable written consent. §1.9.b — individuals own their personal data, likeness, and biometric information; government data collection is subject to strict necessity limits and may not "}, {"id": "s1-9-a", "section": "§1.9.a", "name": "Physical Sovereignty", "text": "Every person has the absolute right to refuse any medical procedure or biological sampling. No mandate is permissible under any declared emergency under any declared emergency unless the individual provides uncoerced, revocable written consent."}, {"id": "s1-9-b", "section": "§1.9.b", "name": "Data Ownership", "text": "Individuals own their personal data, likeness, and biometric information, likeness, and biometric information. Data collected by any government actor is subject to strict necessity limits — it may not be retained beyond the purpose for which it was collected, shared with third parties without..."}, {"id": "s1-9-c", "section": "§1.9.c", "name": "Encryption Protection", "text": "Cryptographic keys are private property. No court or agency may compel their disclosure. Absolute rule, consistent with §1.16's self-incrimination prohibition — closes the digital search-and-seizure loophole present in most existing constitutions."}, {"id": "s1-10", "section": "§1.10", "name": "Inviolability of the Home and Property Rights", "text": "§1.10.a extends \"home\" to all physical residences and digital spaces secured by private cryptographic keys; State access requires a precise warrant recorded on the NRS before execution; general warrants are absolutely prohibited. §1.10.b governs eminent domain: requires proof of absolute public necessity, 150% fair market value payment, NRS recordi"}, {"id": "s1-10-a", "section": "§1.10.a", "name": "Home and Digital Privacy", "text": "'Home' extends to all physical residences and all digital spaces secured by private cryptographic keys. Access requires a warrant specifying the precise data target or physical space, verified on the NRS before execution. General warrants — broad or unspecified authorizations — are absolutely prohibited."}, {"id": "s1-10-b", "section": "§1.10.b", "name": "Eminent Domain", "text": "Seizure of private property requires proof of absolute public necessity, payment of 150% of fair market value, and NRS publication. Private-to-private transfer via eminent domain via eminent domain — using government condemnation to benefit another private party — is constitutionally prohibited."}, {"id": "s1-11", "section": "§1.11", "name": "Self-Defense and the Right to Bear Arms", "text": "The right to keep and bear arms for personal defense and hunting must not be infringed. States may establish proportionate licensing requirements (§1.11.b) but may not impose requirements that function as effective prohibitions on lawful ownership (§1.11.c). The burden of proof lies with the State to demonstrate any challenged requirement is propor"}, {"id": "s1-11-a", "section": "§1.11.a", "name": "Right to Bear Arms", "text": "The right to keep and bear arms for personal defense and hunting must not be infringed. The provision is deliberately narrow in scope — personal defense and hunting — which bounds the right without eliminating it."}, {"id": "s1-11-b", "section": "§1.11.b", "name": "State Licensing Latitude", "text": "States may establish licensing and safety training requirements as a condition of carrying or possessing firearms. States may regulate the exercise of the right but may not use regulation as a prohibition by another name."}, {"id": "s1-11-c", "section": "§1.11.c", "name": "Non-Prohibition Principle", "text": "No State requirement may function as an effective prohibition on keeping or bearing arms. A requirement is an effective prohibition if it imposes costs, delays, or conditions that make lawful ownership practically inaccessible to ordinary citizens. The burden of proof lies with the State to demonstrate proportionality."}, {"id": "s1-12", "section": "§1.12", "name": "Freedom of Movement and Labor", "text": "All Inhabitants have the right to travel and reside anywhere within the Republic. State professional licensing requirements may not create barriers to labor mobility; licenses issued under State law are recognized throughout the Republic. Every person has the right to form and join trade unions and bargain collectively; the right to strike as a col"}, {"id": "s1-13-a", "section": "§1.13.a", "name": "First Appearance", "text": "Any person taken into custody must appear before a judicial officer within 72 hoursMeasured from the moment of physical custody, not from formal arrest. Clock does not pause for weekends or public holidays. of arrest. At the First Appearance, the judge must determine whether custody is lawful and whether conditions of release are appropriate."}, {"id": "s1-13-b", "section": "§1.13.b", "name": "Habeas Corpus Response Deadline", "text": "A court receiving a habeas corpus petition must rule within 48 hours of filing. No procedural rule may extend this deadline. A court that fails to rule within 48 hours is deemed to have found the detention unlawful is deemed to have found the detention unlawful — the detained person must be released or brought before a judicial officer immediately "}, {"id": "s1-13-c", "section": "§1.13.c", "name": "Habeas Corpus", "text": "Any person detained by the State has the absolute right to challenge the lawfulness of their confinement before a judge at any time. The right cannot be suspended by emergency declaration by emergency declaration — it appears in §1.25.b's list of absolutely non-derogable rights."}, {"id": "s1-14-a", "section": "§1.14.a", "name": "Right to Counsel", "text": "Any person accused of a crime or subject to detention has the right to retain and consult with a lawyer before questioning. If they cannot afford counsel, the Republic provides it. The right attaches from the moment of accusation or detention, not from formal charging."}, {"id": "s1-14-b", "section": "§1.14.b", "name": "Caseload Guarantee", "text": "the Legislature must establish maximum caseload limits for publicly funded defense — ensuring that the right to counsel means genuine preparation, not nominal presence. Public defenders must be resourced equivalently to prosecutorial offices handling comparable cases."}, {"id": "s1-14-c", "section": "§1.14.c", "name": "Right to Be Informed of Charges", "text": "Any person detained or accused must be informed promptly, in plain language they understand, of the specific grounds for their detention and the charges being considered. Detention without meaningful explanation of its basis is unconstitutional from its first moment."}, {"id": "s1-14-d", "section": "§1.14.d", "name": "Right to Full Disclosure", "text": "Any accused person has the right to full disclosure of all State evidence — including evidence the prosecution does not intend to use — before trial. Any withholding of exculpatory evidence is a constitutional violation, not a procedural irregularity."}, {"id": "s1-15-a", "section": "§1.15.a", "name": "Speedy Trial Principle", "text": "Every accused person has the right to trial without unreasonable delay. Delay caused by the State is not a neutral fact — prolonged pre-trial detention is itself a punishment imposed without verdict. What constitutes unreasonable delay is defined by the Legislature in statute, subject to judicial review."}, {"id": "s1-15-b", "section": "§1.15.b", "name": "Bail Proportionality", "text": "Pre-trial detention may only be ordered where the court makes a specific, individualized finding that the accused poses a genuine flight risk or documented danger to an identifiable person. Financial inability to post bail does not justify detention — bail conditions must be proportionate to what the accused can actually pay to what the accused can"}, {"id": "s1-15-c", "section": "§1.15.c", "name": "Protection from Trial Penalties", "text": "The right to trial may not be penalized. A defendant who exercises their right to trial may not receive a harsher sentence than they would have received by entering a guilty plea for the same offense. Sentencing 'trial penalties' are constitutionally prohibited."}, {"id": "s1-15-d", "section": "§1.15.d", "name": "Source Code Right", "text": "Any accused person has the right to inspect, challenge, and rebut any algorithm, automated system, statistical model, or raw dataset used as evidence or to generate a score influencing their case. Technology-opaque evidence against which no defense can be mounted is constitutionally inadmissible."}, {"id": "s1-16", "section": "§1.16", "name": "Right to Silence", "text": "No person may be compelled to testify against themselves or to produce self-incriminating evidence. The right of silence is complete — silence may not be commented upon or used to draw adverse inferences or used to draw adverse inferences. Consistent with §1.9.c, this extends to cryptographic keys."}, {"id": "s1-17", "section": "§1.17", "name": "Right to a Public Trial", "text": "Every accused person has the right to a public trial before a judge and, in criminal matters, a jury of peers. Secret or closed proceedings are constitutionally prohibited except for the minimal portion where a specific witness's safety requires it — and even then the verdict must be public. Also permanently unamendable."}, {"id": "s1-18-a", "section": "§1.18.a", "name": "No Retroactive Criminal Laws", "text": "No person may be convicted of an act that was not defined as a criminal offense at the time it was committed. No sentence may exceed the maximum available at the time of the offense. The prohibition on retroactive criminal law is absolute and permanently unamendable."}, {"id": "s1-18-b", "section": "§1.18.b", "name": "Double Jeopardy", "text": "No person may be tried or punished more than once for the same offense arising from the same factual events. Acquittal is final. This applies across all levels of the Republic's court system — a State court acquittal cannot be retried in a federal court on the same facts."}, {"id": "s1-19", "section": "§1.19", "name": "Right to Democratic Participation", "text": "No government action may make voting materially more difficult for any eligible citizen. This covers not only formal disenfranchisement but practical barriers: polling place closures, identification requirements that function as wealth or document-access tests, registration obstacles designed to suppress participation, and reductions in early or ma"}, {"id": "s1-20", "section": "§1.20", "name": "Right to Marry and Found a Family", "text": "The right to marry or form a legally recognized partnership belongs to any two consenting adults regardless of sex, gender, or sexual orientation. The Republic must recognize such partnerships for all legal purposes. The Legislature and States may not create hierarchies of partnership recognition based on the characteristics of the parties."}, {"id": "s1-21", "section": "§1.21", "name": "Rights of Children", "text": "Every child has the right to protection from exploitation, abuse, and neglect. In all State actions affecting minors, the welfare and best interests of the child are the primary consideration — not merely one factor to be weighed. The protection of children is the one area where the Individual Sovereignty Floor explicitly sets 'the primary' rather "}, {"id": "s1-22", "section": "§1.22", "name": "Environmental Accountability", "text": "Article I's environmental provisions establish two constitutional obligations: Government Non-Harm (§1.22.a) prevents authorities from knowingly exposing communities to environmental hazards without disclosure, consultation, and mitigation; Environmental Stewardship (§1.22.b) creates an enforceable duty to maintain ecological integrity. Together th"}, {"id": "s1-22-a", "section": "§1.22.a", "name": "Government Non-Harm", "text": "No government authority may knowingly expose any community of Inhabitants to environmental hazards without full disclosure, meaningful consultation, and proportionate mitigation. The Government Non-Harm principle makes environmental poisoning of communities a a constitutional violation, not merely a policy failure."}, {"id": "s1-22-b", "section": "§1.22.b", "name": "Environmental Stewardship", "text": "The long-term stewardship of the Republic's natural environment is a constitutional obligation of the federal government — not aspirational language. It creates an enforceable duty to maintain ecological integrity that the Inspectorates are mandated to report on annually."}, {"id": "s1-23", "section": "§1.23", "name": "Federal Education Assistance", "text": "Three interlocking education provisions: §1.23.a requires the Republic to fund education assistance so no child's opportunity depends on their territory's wealth. §1.23.b requires public education to equip students to meet the Constitutional Logic Test standard — education for citizenship is a constitutional obligation. §1.23.c preserves parental c"}, {"id": "s1-23-a", "section": "§1.23.a", "name": "Federal Education Assistance", "text": "The Republic must provide adequate education assistance to States and Territories so that no child's educational opportunity is determined primarily by the wealth of their territory. Federal assistance must address the gap between what a jurisdiction can fund locally and what the constitutional literacy standard requires."}, {"id": "s1-23-b", "section": "§1.23.b", "name": "Constitutional Literacy", "text": "The Republic's constitutional literacy standard for citizenship purposes is the CLT, defined in §5.4. Public education must equip students to meet that standard — education for citizenship is a constitutional obligation, not a civic nicety."}, {"id": "s1-23-c", "section": "§1.23.c", "name": "Parental Right", "text": "Parents retain the right to educate children through alternative means — homeschooling, faith-based schools, alternative institutions — provided those alternatives meet the constitutional literacy standard. The Republic may set the floor; it may not mandate the method."}, {"id": "s1-24", "section": "§1.24", "name": "Housing Non-Exclusion", "text": "Article I's housing provisions create constitutional barriers to exclusion and a constitutional obligation to provide. The Non-Exclusion Principle (§1.24.a) prohibits exclusionary zoning and any regulatory mechanism designed to keep certain populations out. The BNF Housing Obligation (§1.24.b) anchors housing as a Basic Needs Floor category — perso"}, {"id": "s1-24-a", "section": "§1.24.a", "name": "Non-Exclusion Principle", "text": "No government authority — federal, State, or local — may use regulatory or land-use powers to exclude any person from access to housing on the basis of any characteristic enumerated in §1.8. Exclusionary zoning designed to keep certain populations out of a community is constitutionally prohibited."}, {"id": "s1-24-b", "section": "§1.24.b", "name": "BNF Housing Obligation", "text": "The Republic's obligation to ensure housing access for persons who cannot independently secure it is part of the Basic Needs Floor under §10.1. This provision anchors housing as a BNF category and makes housing exclusion an enforceable constitutional violation."}, {"id": "s1-25-a", "section": "§1.25.a", "name": "Emergency Derogation — Declaration Requirements", "text": "Emergency derogation of Article I rights requires a precisely structured declaration specifying: the nature of the emergency, which rights are limited, the geographic scope, the duration, and the review mechanism. The specificity requirement prevents open-ended emergency licenses — the government must commit in advance to exactly what it is doing, "}, {"id": "s1-25-b", "section": "§1.25.b", "name": "Non-Derogable Rights", "text": "These five rights are absolute under any circumstances: the prohibition on torture (§1.2); slavery (§1.3); habeas corpus (§1.13); the right to a public trial (§1.17); and no retroactive punishment (§1.18)."}, {"id": "s1-25-c", "section": "§1.25.c", "name": "Inspectorate Continuity", "text": "The three Inspectorates continue to operate with full constitutional authority throughout any emergency — they cannot be suspended or have their mandate reduced by emergency declaration. Accountability infrastructure is precisely most important when emergency powers are active."}, {"id": "s1-25-d", "section": "§1.25.d", "name": "Automatic Expiry and Judicial Review", "text": "Emergency measures lapse automatically at the expiry of the Declaration. Judicial review of any emergency measure is available to any citizen at any time, and courts may rule during the emergency that a specific measure is unconstitutional."}, {"id": "s1-25-e", "section": "§1.25.e", "name": "No Permanent Emergency", "text": "No emergency measure may be made permanent by legislative act. Every emergency measure lapses automatically at the expiry of the Declaration unless re-enacted through the ordinary legislative process. The Legislature may not extend an emergency measure by re-declaration within 60 days of its expiry, or at all unless a 2/3 majority certifies continu"}, {"id": "s1-26", "section": "§1.26", "name": "Associated Community Residents", "text": "Every person residing within any Associated Community operating under a compact with the Republic holds the full protections of Article I, enforceable directly by federal courts regardless of the Associated Community's internal governance structure. No compact provision may limit or qualify any Article I right for any resident of Associated Communi"}, {"id": "s1-27", "section": "§1.27", "name": "Non-Refoulement", "text": ""}, {"id": "s1-28", "section": "§1.28", "name": "Medical Autonomy", "text": "Medical decisions belong to the patient and their licensed provider — not to the State. The first paragraph establishes this as a constitutional principle: government cannot require or forbid specific treatments in the individual patient-provider relationship. The State's legitimate role is safety and standards: licensing, scope of practice, qualit"}, {"id": "s1-29", "section": "§1.29", "name": "Right to Privacy", "text": "The general right to privacy is the interpretive umbrella over all specific privacy protections in the constitution. A person has the right to privacy in their person, home, communications, associations, health, and personal data — the enumeration signals breadth, not limitation. The general right governs wherever no specific provision addresses th"}, {"id": "s1-29-a", "section": "§1.29.a", "name": "Searches and Seizures", "text": "No unreasonable search or seizure of person, home, property, communications, or data. Any authorized search must be narrowly scoped, judicially approved before execution, and recorded on the NRS. General warrants — broad or unspecified authorizations — are absolutely prohibited. Digital spaces secured by private cryptographic keys are treated as eq"}, {"id": "s1-29-b", "section": "§1.29.b", "name": "Medical Privacy", "text": "Medical information, health records, genetic data, and bodily condition are private. Government compulsion requires a specific judicial order in active legal proceedings, limited to what those proceedings directly require. Public health law disclosures must be proportionate, time-limited, and NRS-recorded. This provision is distinct from §1.28 Medi"}, {"id": "s1-29-c", "section": "§1.29.c", "name": "Communications and Data", "text": "Government collection of private communications or personal data requires specific judicial authorization identifying the person, the data sought, and the collection period. Bulk collection — without individual identification — is prohibited outright. Private-sector entities cannot be compelled to collect or disclose on government's behalf beyond w"}, {"id": "s1-29-d", "section": "§1.29.d", "name": "Intelligence Firewall", "text": "Migrated from §12.3 with language unchanged. All domestic intelligence operations against Republic citizens are permanently prohibited and constitutionally void. Any such order is reported to the NRS by the EI. This prohibition is non-derogable — no emergency, treaty, or statute can suspend it. Placed in Article I rather than Article XII because it"}, {"id": "s1-29-e", "section": "§1.29.e", "name": "Associational Privacy", "text": "The explicit provision that closes the gap between freedom of association (§1.6) and privacy in associations. §1.6 protects the right to associate; §1.29.e protects the right to keep private who you associate with and the fact that you do. A government can comply with §1.6 while violating §1.29.e — it can refrain from prohibiting membership while s"}, {"id": "s2-1", "section": "§2.1", "name": "The President — Term and Transfer", "text": ""}, {"id": "s2-1-ac", "section": "§2.1.a–c", "name": "Military Authority — Three Tiers", "text": ""}, {"id": "s2-1-a", "section": "§2.1.a", "name": "Tier 1 — Immediate Defensive Response", "text": ""}, {"id": "s2-1-b", "section": "§2.1.b", "name": "Tier 2 — Senate Armed Services Authorization", "text": ""}, {"id": "s2-1-c", "section": "§2.1.c", "name": "Tier 3 — Legislative Declaration of Defense", "text": ""}, {"id": "s2-1-d", "section": "§2.1.d", "name": "Funding Lock", "text": ""}, {"id": "s2-1-e", "section": "§2.1.e", "name": "Privacy Firewall", "text": "Cross-references §1.29.d as the authoritative Intelligence Firewall provision. The prohibition on domestic intelligence operations against Republic citizens is non-derogable and permanent — governed by §1.29.d. §2.1.e previously restated the prohibition in language not identical to §1.29.d. Now redirects all references to §1.29.d. Any order in viol"}, {"id": "s2-1-f", "section": "§2.1.f", "name": "Presidential Veto — Scope", "text": ""}, {"id": "s2-1-f-i", "section": "§2.1.f.i", "name": "Judicial Review and Override", "text": ""}, {"id": "s2-1-g", "section": "§2.1.g", "name": "Presidential Clemency", "text": ""}, {"id": "s2-1-h", "section": "§2.1.h", "name": "Dual Executive Conflict Resolution During Active Operations", "text": ""}, {"id": "s2-1-i", "section": "§2.1.i", "name": "International Trade Authority", "text": ""}, {"id": "s2-1-j", "section": "§2.1.j", "name": "Presidential Officer Appointments and Removal", "text": ""}, {"id": "s2-2", "section": "§2.2", "name": "The Prime Minister — Domestic Executive Domain", "text": ""}, {"id": "s2-2-a", "section": "§2.2.a", "name": "The Record System Mandate", "text": ""}, {"id": "s2-2-b", "section": "§2.2.b", "name": "Duty of Refusal", "text": ""}, {"id": "s2-2-c", "section": "§2.2.c", "name": "PM Maximum Consecutive Service", "text": ""}, {"id": "s2-2-d", "section": "§2.2.d", "name": "Civil Service Integrity", "text": ""}, {"id": "s2-2-e", "section": "§2.2.e", "name": "Domestic Emergency Authority", "text": ""}, {"id": "s2-2-f", "section": "§2.2.f", "name": "PM Clemency", "text": ""}, {"id": "s2-2-g", "section": "§2.2.g", "name": "Ministerial Appointments", "text": ""}, {"id": "s2-2-h", "section": "§2.2.h", "name": "Administrative Acting Officer Framework", "text": ""}, {"id": "s2-3-a", "section": "§2.3.a", "name": "Selection", "text": ""}, {"id": "s2-3-b", "section": "§2.3.b", "name": "Constructive Vote of No Confidence", "text": ""}, {"id": "s2-3-c", "section": "§2.3.c", "name": "Caretaker Protocol", "text": ""}, {"id": "s2-4-ab", "section": "§2.4.a–b", "name": "Suspensive Veto and Fiscal Objection", "text": ""}, {"id": "s2-4-a", "section": "§2.4.a", "name": "Suspensive Veto", "text": ""}, {"id": "s2-4-b", "section": "§2.4.b", "name": "Fiscal Objection", "text": ""}, {"id": "s2-4-c", "section": "§2.4.c", "name": "Objection Limits", "text": ""}, {"id": "s2-5-a", "section": "§2.5.a", "name": "Emergency Legislative Continuity", "text": ""}, {"id": "s2-6", "section": "§2.6", "name": "Presidential Succession", "text": ""}, {"id": "s2-6-a", "section": "§2.6.a", "name": "Presidential Succession Line", "text": ""}, {"id": "s2-6-b", "section": "§2.6.b", "name": "Incapacity Certification", "text": ""}, {"id": "s2-6-c", "section": "§2.6.c", "name": "Succession-Based Presidential Term", "text": ""}, {"id": "s2-8", "section": "§2.8", "name": "Emergency Governance Protocol", "text": ""}, {"id": "s2-9-b", "section": "§2.9.b", "name": "Legislative Amnesty", "text": ""}, {"id": "s2-9-c", "section": "§2.9.c", "name": "Self-Clemency Absolute Prohibition", "text": ""}, {"id": "s2-9-d", "section": "§2.9.d", "name": "Cross-Chamber Clemency Review", "text": ""}, {"id": "s2-10", "section": "§2.10", "name": "Presidential Removal — Two Political Tracks", "text": ""}, {"id": "s2-10-a", "section": "§2.10.a", "name": "Legislative Removal", "text": ""}, {"id": "s2-10-b", "section": "§2.10.b", "name": "Senate Referral to Popular Recall", "text": ""}, {"id": "s2-10-c", "section": "§2.10.c", "name": "One Referral Per Term", "text": "No second Senate referral to popular recall within the same presidential term. One-shot rule prevents a hostile Senate from using repeated recall elections as attrition. After a failed recall, the President serves out their term with the NRS record intact."}, {"id": "s3-1-a", "section": "§3.1.a", "name": "House Membership Floor", "text": "The House is the proportional chamber — seats allocated by population, minimum one per State, floor of one per 750,000 citizens, self-scaling with population. The opening sentence previously read \"the Legislature is the Republic's legislature\" — circular and uninformative. Now reads \"The Republic's legislature is bicameral.\" The Legislature may set"}, {"id": "s3-1-b", "section": "§3.1.b", "name": "Census Authority", "text": "The population census is conducted by the Legislative Inspectorate. The provision previously contained a lengthy inline explanation of why the LI (not the EI) conducts the census — accurate but belonging in commentary. Operative rule only: LI conducts the census."}, {"id": "s3-1-c", "section": "§3.1.c", "name": "Single-Subject Rule", "text": ""}, {"id": "s3-1-d", "section": "§3.1.d", "name": "Bill Exposure", "text": ""}, {"id": "s3-1-e", "section": "§3.1.e", "name": "Caretaker Activation and PM Formation", "text": ""}, {"id": "s3-1-f", "section": "§3.1.f", "name": "House Term Limits", "text": ""}, {"id": "s3-2", "section": "§3.2", "name": "The Senate — States as Constitutional Actors", "text": ""}, {"id": "s3-2-a", "section": "§3.2.a", "name": "Senator Terms and Limits", "text": ""}, {"id": "s3-2-b", "section": "§3.2.b", "name": "Senate Speaker Role Limit", "text": ""}, {"id": "s3-2-c", "section": "§3.2.c", "name": "Senate Must Act on Every House Bill", "text": ""}, {"id": "s3-2-d", "section": "§3.2.d", "name": "Judicial Confirmation", "text": ""}, {"id": "s3-2-e", "section": "§3.2.e", "name": "Treaty Ratification", "text": ""}, {"id": "s3-2-e-i", "section": "§3.2.e.i", "name": "Treaty Domestic Application", "text": ""}, {"id": "s3-2-e-ii", "section": "§3.2.e.ii", "name": "Treaty Withdrawal", "text": ""}, {"id": "s3-2-f", "section": "§3.2.f", "name": "Impeachment Trials", "text": ""}, {"id": "s3-2-g", "section": "§3.2.g", "name": "Survivor Quorum — Catastrophic Casualty Events", "text": ""}, {"id": "s3-2-h", "section": "§3.2.h", "name": "Senate Speaker Vacancy", "text": ""}, {"id": "s3-2-i", "section": "§3.2.i", "name": "Senate Amendment Authority", "text": ""}, {"id": "s3-3-a", "section": "§3.3.a", "name": "Legislative Mandate Enforcement", "text": ""}, {"id": "s3-3-b", "section": "§3.3.b", "name": "Standard Passage", "text": ""}, {"id": "s3-3-c", "section": "§3.3.c", "name": "Presidential Veto Override", "text": ""}, {"id": "s3-3-d", "section": "§3.3.d", "name": "Record System Entry", "text": ""}, {"id": "s3-4", "section": "§3.4", "name": "Electoral Districts", "text": ""}, {"id": "s3-4-a", "section": "§3.4.a", "name": "Criteria Hierarchy", "text": ""}, {"id": "s3-4-b", "section": "§3.4.b", "name": "Prohibited Inputs", "text": ""}, {"id": "s3-4-c", "section": "§3.4.c", "name": "Drawing Authority — States", "text": ""}, {"id": "s3-4-d", "section": "§3.4.d", "name": "Drawing Authority — Federal Territories", "text": ""}, {"id": "s3-4-e", "section": "§3.4.e", "name": "National Compliance Review", "text": ""}, {"id": "s3-4-f", "section": "§3.4.f", "name": "Court Adjudication", "text": ""}, {"id": "s3-4-g", "section": "§3.4.g", "name": "Continuity", "text": ""}, {"id": "s3-5", "section": "§3.5", "name": "Impeachment", "text": ""}, {"id": "s3-5-a", "section": "§3.5.a", "name": "Impeachment Inquiry", "text": ""}, {"id": "s3-5-b", "section": "§3.5.b", "name": "Articles of Impeachment", "text": ""}, {"id": "s3-5-c", "section": "§3.5.c", "name": "Senate Trial", "text": ""}, {"id": "s3-5-d", "section": "§3.5.d", "name": "Executive Continuity During Impeachment", "text": ""}, {"id": "s3-6-a", "section": "§3.6.a", "name": "House Expulsion", "text": ""}, {"id": "s3-6-b", "section": "§3.6.b", "name": "Senate Expulsion", "text": ""}, {"id": "s3-6-c", "section": "§3.6.c", "name": "Anti-Weaponization Threshold", "text": ""}, {"id": "s3-6-d", "section": "§3.6.d", "name": "Consequences and Restoration", "text": ""}, {"id": "s3-6-e", "section": "§3.6.e", "name": "Recall — States and Territories", "text": ""}, {"id": "s3-6-f", "section": "§3.6.f", "name": "Vacancy Filling — States and Territories", "text": ""}, {"id": "s3-7-a", "section": "§3.7.a", "name": "Authorization", "text": ""}, {"id": "s3-7-b", "section": "§3.7.b", "name": "Appointment", "text": ""}, {"id": "s3-7-c", "section": "§3.7.c", "name": "Removal", "text": ""}, {"id": "s3-7-d", "section": "§3.7.d", "name": "Oversight", "text": ""}, {"id": "s3-7-e", "section": "§3.7.e", "name": "Limits", "text": "Any citizen, State government, or parliamentary minority of 1/3 may challenge a proposed district map by petitioning the SC within the 60-day review period after LI compliance certification. The Court reviews whether criteria were correctly applied — not whether a different map would have been better."}, {"id": "s4-1-a", "section": "§4.1.a", "name": "Establishment", "text": ""}, {"id": "s4-1-b", "section": "§4.1.b", "name": "Appointment of Inferior Courts", "text": "PM nominates within 90 days; the Senate confirms by a supermajority (55–67% of full seated membership). Senate confirmation is consistent with §3.2.d and the Senate's established checking role throughout the constitution — the House creates inferior courts by statute (§4.1.a); the Senate confirms the judges who sit on them. If the Senate fails to a"}, {"id": "s4-1-c", "section": "§4.1.c", "name": "Judicial Tenure Protection", "text": ""}, {"id": "s4-1-d", "section": "§4.1.d", "name": "Judicial Removal", "text": ""}, {"id": "s4-2", "section": "§4.2", "name": "Open-Candidacy Judicial Selection", "text": ""}, {"id": "s4-2-a", "section": "§4.2.a", "name": "Candidate Registration", "text": ""}, {"id": "s4-2-b", "section": "§4.2.b", "name": "Judicial Selection Board", "text": ""}, {"id": "s4-2-c", "section": "§4.2.c", "name": "Judicial Inspectorate Certification", "text": ""}, {"id": "s4-2-d", "section": "§4.2.d", "name": "Public Election", "text": ""}, {"id": "s4-2-e", "section": "§4.2.e", "name": "Mid-Term Vacancies", "text": ""}, {"id": "s4-2-f", "section": "§4.2.f", "name": "Emergency Panel for Tier 1 Scope Challenges", "text": ""}, {"id": "s4-2-g", "section": "§4.2.g", "name": "Vacancy Operating Rules", "text": ""}, {"id": "s4-2-h", "section": "§4.2.h", "name": "Judicial Recusal", "text": ""}, {"id": "s4-3-a", "section": "§4.3.a", "name": "Concrete Cases Only", "text": ""}, {"id": "s4-3-b", "section": "§4.3.b", "name": "Organizational Standing", "text": ""}, {"id": "s4-3-c", "section": "§4.3.c", "name": "Ripeness and Mootness", "text": ""}, {"id": "s4-3-d", "section": "§4.3.d", "name": "Original Jurisdiction", "text": ""}, {"id": "s4-3-e", "section": "§4.3.e", "name": "Inspectorate Findings in Constitutional Proceedings", "text": ""}, {"id": "s4-4-a", "section": "§4.4.a", "name": "Judicial Judgments", "text": "Non-recognition grounds are exhaustive: the issuing court lacked jurisdiction; the judgment was obtained by fraud; enforcement would require an act the Legislature has defined as categorically unenforceable. A fourth ground — facially contrary to Article I — was removed as redundant. §15.6 Constitutional Supremacy already makes judgments contrary t"}, {"id": "s4-4-b", "section": "§4.4.b", "name": "NRS Authentication", "text": ""}, {"id": "s4-4-c", "section": "§4.4.c", "name": "Public Acts and Official Records", "text": "Official records on the NRS are self-authenticating — no re-certification required. Professional licenses receive equivalent recognition across all States and Territories. The Legislature latitude language previously allowing the Legislature to define the \"permissible scope\" of supplementary requirements has been removed. §1.12 already prohibits st"}, {"id": "s4-4-d", "section": "§4.4.d", "name": "Status Orders — Special Protections", "text": ""}, {"id": "s4-4-e", "section": "§4.4.e", "name": "Limits — No Obligation Beyond Republic Borders", "text": ""}, {"id": "s4-4-f", "section": "§4.4.f", "name": "Legislative Implementation Mandates", "text": "Finality rule is now permanent rather than a default pending legislation. A judgment is final for §4.4.a purposes if it is not subject to an automatic stay under the issuing jurisdiction's procedural law, regardless of whether an appeal is pending. The Legislature may refine the finality standard for specific categories but cannot use pending-appea"}, {"id": "s5-1-a", "section": "§5.1.a", "name": "Inherent Citizenship", "text": "A child is automatically a citizen at birth if at least one parent is a Citizen or Legal Resident at the time of birth. Statelessness prevention clause: where a child would otherwise be stateless, citizenship is granted regardless of parental status. No citizenship may be stripped from a natural-born citizen."}, {"id": "s5-1-a-i", "section": "§5.1.a.i", "name": "Statelessness Prevention", "text": "A child born on Republic territory to parents holding neither Citizen nor Legal Resident status is an Inhabitant from birth, with full Article I protections and BNF access. Where no country recognizes the child as a citizen, the Republic provides a determination process consistent with §6.4's protection principles — protection first, determination "}, {"id": "s5-1-b", "section": "§5.1.b", "name": "Coming of Age", "text": "Children of citizens are Inhabitants at birth with full Article I protections. Full citizenship rights — including the right to vote — activate at 18. The distinction between Inhabitant and Citizen status for citizen children prevents citizenship from being used to exempt children from local law."}, {"id": "s5-1-c", "section": "§5.1.c", "name": "Naturalization", "text": "A Legal Resident may earn citizenship after five continuous years of residency, passing the Constitutional Logic Test, and demonstrating a working knowledge of the Republic's official language. The CLT tests understanding of the Republic's constitutional structure of the Republic's constitutional structure — not cultural assimilation."}, {"id": "s5-1-d", "section": "§5.1.d", "name": "National Service Path", "text": "A Legal Resident may earn citizenship through honorable completion of military or national service — a service path that runs parallel to the residency path. Years of service are a legitimate basis for constitutional membership."}, {"id": "s5-1-e", "section": "§5.1.e", "name": "Citizenship Irrevocability", "text": "Citizenship may not be revoked as punishment or for any reason once granted by birth or naturalization. The Republic may not manufacture statelessness as a punitive tool. See also §5.1.a.i, which ensures children born on Republic territory to undocumented parents cannot be left stateless by inaction."}, {"id": "s5-1-f", "section": "§5.1.f", "name": "Derivative Status", "text": "A child born before a parent acquired Legal Residency or Citizenship, who accompanies that parent to the Republic within a Legislature-defined window, receives derivative status. Prevents a parent's pre-Republic legal status from permanently cutting off their child's path to citizenship."}, {"id": "s5-1-g", "section": "§5.1.g", "name": "Accelerated Naturalization — Long-Term Pre-Ratification Residents", "text": "Any person who resided continuously in the Republic's territory for 5+ years immediately before Day Zero but did not hold predecessor voting rights — including persons disenfranchised by laws subsequently nullified under §19.2 — may apply for citizenship through an accelerated process the Legislature must establish within one year of Phase 4. The p"}, {"id": "s5-2", "section": "§5.2", "name": "Legal Resident Rights", "text": "Legal Residents hold a Residency Credential allowing them to work, enter contracts, own property, access BNF programs, and participate in local elections where the Legislature authorizes. They hold all Article I rights as Inhabitants. What they lack that citizens hold: federal voting rights and the right to stand for federal office."}, {"id": "s5-3", "section": "§5.3", "name": "Custodial Care of Citizen Children", "text": "Where a parent or guardian who is the primary caregiver of a citizen child is removed from the Republic, the Republic accepts responsibility for that citizen child — housing, care, and connection to remaining family. The Republic does not separate citizen children from their sole caregivers from their sole caregivers without providing for them."}, {"id": "s5-4", "section": "§5.4", "name": "The Constitutional Logic Test", "text": "The CLT is required for earned citizenship through naturalization (§5.1.c) and national service (§5.1.d). It tests knowledge of constitutional principles and civic structure — not political opinions or cultural loyalty. The Senate deadlock rule (§5.4.c) ensures the existing test remains in force if the Legislature cannot agree on a new standard."}, {"id": "s5-4-a", "section": "§5.4.a", "name": "Senate Authority over the CLT Standard", "text": "The constitutional floor is stated directly in §5.4: the test must assess knowledge sufficient to understand the structure, powers, limits, and rights established by this Constitution. Any statute reducing the CLT below this floor is void and any citizen may challenge it in court. The Senate sets the standard by statute — raising it by simple major"}, {"id": "s5-4-b", "section": "§5.4.b", "name": "CLT Administrator", "text": "The Constitutional Logic Test is administered by a CLT Administrator nominated by the PM from a Candidate Register, confirmed by the Senate. Structural independence from partisan influence: the CLT process cannot be used to create barriers that track political outcomes."}, {"id": "s5-4-c", "section": "§5.4.c", "name": "Status Quo Maintenance", "text": "Senate deadlock on CLT standard changes keeps the existing version in force. Deadlock cannot be weaponized to eliminate the CLT or make it impossibly difficult — the existing test remains operative."}, {"id": "s5-5-a", "section": "§5.5.a", "name": "Automatic Citizenship Grant", "text": "All individuals holding voting rights on Day Zero of ratification are automatically granted full citizenship without testing or application. The Day Zero Grandfather Clause prevents the new Republic from immediately disenfranchising its existing population by requiring existing voters to re-qualify under new standards."}, {"id": "s6-1-ab", "section": "§6.1.a–b", "name": "The Dual Gate", "text": "Legal residency requires passing both gates. Gate 1 is the federal substantive assessment — national standards that no State can circumvent. Gate 2 is State acceptance — no State can be forced to absorb unlimited immigration obligations without its participation. The dual-gate architecture prevents two failure modes simultaneously: race-to-the-bott"}, {"id": "s6-1", "section": "§6.1", "name": "The Dual-Gate System", "text": "Every immigration application must clear two sequential gates: Gate 1 (state sponsorship) and Gate 2 (federal certification). The Legislature holds supreme authority over immigration — it sets the standards for both gates and may set aggregate limits on total applications processed in any period, provided limits are applied without §1.8 discriminat"}, {"id": "s6-1-a", "section": "§6.1.a", "name": "Gate 1 — State Sponsorship", "text": "A sponsoring State certifies the applicant through its own vetting process and accepts notification obligations during the application period. During the application period the applicant must maintain a genuine connection to the sponsoring State — as the Legislature defines by statute — so that notification obligations remain practical rather than "}, {"id": "s6-1-b", "section": "§6.1.b", "name": "Gate 2 — Federal Certification", "text": "Federal certification across four statutory categories: identity verification, criminal history, national security assessment, self-sufficiency or support guarantee. Cannot impose ideological screening or nationality-based quotas. Any denial must specify the precise ground in writing. National security denials published in redacted form protecting "}, {"id": "s6-1-c", "section": "§6.1.c", "name": "Presidential Role", "text": "Once an applicant clears both gates, the President must ministerially issue residency credentials. The word 'ministerially' is deliberate — the President has no discretion to refuse or delay what the law requires. Presidential interference with credential issuance is constitutionally prohibited."}, {"id": "s6-1-d", "section": "§6.1.d", "name": "Federal Sponsorship Category", "text": "The Legislature may establish a Federal Sponsorship Category where designated federal agencies serve as Gate 1 sponsors for applicants whose skills directly serve a defined federal interest — research programs, national infrastructure, national security-adjacent technical roles. The agency assumes all State Gate 1 responsibilities including notific"}, {"id": "s6-2", "section": "§6.2", "name": "Enforcement and Removal", "text": "Only the federal government may remove individuals from the Republic — States may not conduct deportations independently. This prevents States from developing parallel immigration enforcement regimes that could be used to target populations the State government dislikes regardless of federal law. Removal occurs only for violations of laws the Legis"}, {"id": "s6-3", "section": "§6.3", "name": "Gate 2 Appeal Rights", "text": "Gate 2 denials are judicially challengeable on three grounds: criterion outside the four certified categories; denial made on discriminatory grounds contrary to §1.8; or procedural violation affecting the outcome. Gate 1 denials — a state's decision not to sponsor — are not subject to federal review on the merits of the sponsorship decision. Howeve"}, {"id": "s6-3-a", "section": "§6.3.a", "name": "Judicial Challenge", "text": "An applicant may challenge a Gate 2 denial on three grounds: criterion outside the four certified categories; discriminatory application; or procedurally deficient process. Three-ground limitation channels challenges rather than eliminating them."}, {"id": "s6-3-b", "section": "§6.3.b", "name": "National Security Denials — In-Camera Review", "text": "Where Gate 2 is denied on national security grounds, a reviewing court may examine the classified assessment in camera and determine whether it constitutes a credible, specific, and documented concern — without publishing classified content. The in-camera review is outcome-determinative: either the security concern meets the constitutional standard"}, {"id": "s6-4", "section": "§6.4", "name": "Asylum and Protection", "text": "Asylum proceedings operate on a separate constitutional track from the dual-gate immigration system. An asylum filer under §1.27 becomes an Inhabitant at filing — not upon grant. Their claim must be determined before any removal order takes effect. The asylum track is explicitly exempt from Gate 1 state sponsorship: no state's refusal to sponsor ca"}, {"id": "s6-4-a", "section": "§6.4.a", "name": "Asylum Seekers as Inhabitants", "text": "Any person who files an asylum claim under §1.27 is an Inhabitant of the Republic from the date of filing — immediately entitled to BNF coverage and all Article I protections. Protection-first: the determination process does not happen in a rights-free zone."}, {"id": "s6-4-b", "section": "§6.4.b", "name": "Right to Determination and Protection During Proceedings", "text": "Asylum proceedings must provide: a qualified adjudicator with decision authority, access to an interpreter, the right to present evidence and witnesses, a written decision specifying grounds, and a right of appeal. Standards apply regardless of the applicant's point of entry into the Republic."}, {"id": "s6-4-c", "section": "§6.4.c", "name": "Asylum Court", "text": "The Asylum Court is a federal judicial institution constitutionally independent of both executive branches. Its judges hold full tenure protections. The Legislature may not establish any asylum determination body as a subdivision or instrumentality of either executive branch — administrative asylum tribunals dependent on the executive are constitut"}, {"id": "s6-4-d", "section": "§6.4.d", "name": "Non-Penalization for Irregular Entry", "text": "The manner or means of entry into the Republic — including irregular or unauthorized entry — does not affect the right to claim asylum or have that claim determined. No penalty arising solely from irregular entry may be imposed on a person whose asylum claim is pending or has been granted."}, {"id": "s6-4-e", "section": "§6.4.e", "name": "Unexecutable Removal Orders", "text": "Legislature must define a minimum status, material conditions, and periodic judicial review for persons subject to final removal orders that cannot be executed — because the destination country won't accept them, or execution would violate §1.27. The constitution does not allow indefinite stateless detention."}, {"id": "s6-4-f", "section": "§6.4.f", "name": "Security and Criminal Protection Cases", "text": "Where the Asylum Court grants §1.27 protection to a person who poses a documented security threat, removal remains constitutionally barred — but indefinite unreviewed detention is not constitutionally available. The Legislature must establish a framework with regular judicial review. 'Indefinite unreviewed detention is not a constitutionally availa"}, {"id": "s6-4-g", "section": "§6.4.g", "name": "Territory Accessibility", "text": "The asylum proceedings statute must ensure asylum is accessible to persons in Territories and geographically remote areas — not just major population centers. The right to seek asylum applies regardless of where in the Republic a person arrives."}, {"id": "s6-4-h", "section": "§6.4.h", "name": "Unaccompanied Minors", "text": "An unaccompanied minor arriving in the Republic or presenting to Republic authorities is an Inhabitant from the moment of contact and holds full §1.27 protection. A federal legal guardian must be appointed within 24 hours. No unaccompanied minor may be detained in a facility not specifically designated and resourced for children."}, {"id": "s7-1", "section": "§7.1", "name": "Standard Elections — Ranked Choice", "text": "All federal elections on National Election Day, every two years. All elections for House, Senate, SC, and Electoral Commission seats use Ranked Choice Voting — majority required, not plurality. No federal elections outside National Election Day except special elections for vacancies. This concentrates democratic attention and ensures all federal of"}, {"id": "s7-2-a", "section": "§7.2.a", "name": "National Ranked-Choice Vote", "text": "Presidential elections use RCV nationally, preventing the geographic distortions of district-based winner-take-all systems. Votes transfer until one candidate holds a majority of active ballots nationwide. The national RCV tends to produce presidents who are the genuine second or third choice of a larger electorate — a broader mandate than first-pr"}, {"id": "s7-2-b", "section": "§7.2.b", "name": "The Combined Score", "text": "Where no candidate achieves a national RCV majority, the combined score mechanism favors the candidate with the broadest geographic distribution of support. A candidate who wins large margins in a few populous regions but has near-zero support elsewhere represents a fundamentally different governing coalition than a candidate with narrower leads di"}, {"id": "s7-2-c", "section": "§7.2.c", "name": "Presidential Election Regions", "text": "Presidential election regions provide the geographic breadth component of the combined score, ensuring that a winning candidate builds support across the Republic's geographic spread rather than only its population centres. Regions are drawn by the Electoral Commission — which already manages elections and electoral geography — using the same crite"}, {"id": "s7-2-d", "section": "§7.2.d", "name": "Territory Presidential Voting", "text": "Territory citizens hold the full §1.19 right to vote in presidential elections. Their votes count in the national first-preference total — the 65% component of the combined score — but Territories are not assigned to presidential election regions and do not contribute to the 35% regional breadth component. The regional breadth measure reflects the "}, {"id": "s7-2-e", "section": "§7.2.e", "name": "Election Certification", "text": "The Electoral Commission certifies the final presidential election result to the NRS within a period the Legislature defines by statute. Certification is final and may be challenged only before the Supreme Court within 14 days. No transfer of presidential authority may be delayed beyond the constitutionally fixed moment."}, {"id": "s7-2-f", "section": "§7.2.f", "name": "Run-off", "text": "If two candidates are within 0.5% of each other on the combined score, a head-to-head national RCV runoff is conducted between those two candidates. The runoff closes the edge-case gap where the combined score is mathematically indeterminate."}, {"id": "s7-3-a", "section": "§7.3.a", "name": "No Executive Interference", "text": "The President may not declare, postpone, or influence the scheduling of elections — including declaring emergencies that have the effect of postponing them. §1.25.e's prohibition on emergency-based election postponement backs this up: even a genuine emergency cannot defer a scheduled election."}, {"id": "s7-3-b", "section": "§7.3.b", "name": "National Voting System", "text": "The Electoral Commission administers the National Voting System through which all federal elections and referenda are conducted. The NVS is constitutionally required to maintain ballot secrecy, public auditability, and resilience — properties defined in Article XVI creating a cross-constitutional guarantee."}, {"id": "s7-3-c", "section": "§7.3.c", "name": "Participation Protection", "text": "No State may take any action that reduces NVS access, functionality, or availability within its territory. State-level voter suppression — long lines, ID requirements that function as bars, polling place closures that reduce access — is constitutionally prohibited to the extent it reduces access for eligible citizens."}, {"id": "s8-1", "section": "§8.1", "name": "Three Inspectorates", "text": ""}, {"id": "s8-1-a", "section": "§8.1.a", "name": "The Legislative Inspectorate (LI)", "text": ""}, {"id": "s8-1-b", "section": "§8.1.b", "name": "The Executive Inspectorate (EI)", "text": ""}, {"id": "s8-1-c", "section": "§8.1.c", "name": "The Judicial Inspectorate (JI)", "text": ""}, {"id": "s8-2", "section": "§8.2", "name": "Selection and Independence", "text": ""}, {"id": "s8-3-a", "section": "§8.3.a", "name": "Legislative IG", "text": ""}, {"id": "s8-3-b", "section": "§8.3.b", "name": "Executive IG", "text": ""}, {"id": "s8-3-c", "section": "§8.3.c", "name": "Term and Staggering", "text": ""}, {"id": "s8-4-a", "section": "§8.4.a", "name": "Judicial IG Candidate Pool", "text": ""}, {"id": "s8-4-b", "section": "§8.4.b", "name": "The Draw", "text": ""}, {"id": "s8-4-c", "section": "§8.4.c", "name": "Term and Pool Depletion", "text": ""}, {"id": "s8-4-d", "section": "§8.4.d", "name": "Inspectorate Staff Continuity", "text": ""}, {"id": "s8-4-e", "section": "§8.4.e", "name": "Supreme Court Candidate Registry", "text": ""}, {"id": "s8-5-a", "section": "§8.5.a", "name": "For-Cause Removal", "text": ""}, {"id": "s8-5-b", "section": "§8.5.b", "name": "No-Cause Removal", "text": ""}, {"id": "s8-5-c", "section": "§8.5.c", "name": "Judicial IG — For-Cause Only", "text": ""}, {"id": "s8-6-a", "section": "§8.6.a", "name": "Reports", "text": ""}, {"id": "s8-6-b", "section": "§8.6.b", "name": "No Classification", "text": ""}, {"id": "s8-6-c", "section": "§8.6.c", "name": "No Binding Force", "text": ""}, {"id": "s8-6-d", "section": "§8.6.d", "name": "Non-Pursuit Disclosure", "text": ""}, {"id": "s8-6-e", "section": "§8.6.e", "name": "Minority Reports", "text": ""}, {"id": "s8-6-f", "section": "§8.6.f", "name": "Inspectorate Funding Guarantee", "text": ""}, {"id": "s8-6-g", "section": "§8.6.g", "name": "Citizen Discrepancy Petition", "text": ""}, {"id": "s8-7", "section": "§8.7", "name": "Triggered Investigations", "text": ""}, {"id": "s8-7-a", "section": "§8.7.a", "name": "Official Trigger", "text": ""}, {"id": "s8-8-b", "section": "§8.8.b", "name": "Publication", "text": ""}, {"id": "s8-9", "section": "§8.9", "name": "Inspectorate Oversight — State Designee Panel", "text": ""}, {"id": "s8-9-a", "section": "§8.9.a", "name": "Single Mandate", "text": ""}, {"id": "s8-9-b", "section": "§8.9.b", "name": "Appeals", "text": ""}, {"id": "s8-9-d", "section": "§8.9.d", "name": "Gatekeeping Appeal", "text": ""}, {"id": "s8-10", "section": "§8.10", "name": "Inspectorate Minimum Funding Guarantee", "text": ""}, {"id": "s8-11", "section": "§8.11", "name": "Eighth-Year Assessment", "text": "The eight-year joint assessment is the constitution's built-in self-evaluation mechanism — the document asking whether it is working as designed. Every eight years, the three Inspectorates jointly assess constitutional performance across all domains: Are rights enforced? Is the Inspectorate reporting mechanism functioning or being abused? Are fisca"}, {"id": "s9-1", "section": "§9.1", "name": "NRS Properties", "text": ""}, {"id": "s9-1-a", "section": "§9.1.a", "name": "Immutability", "text": ""}, {"id": "s9-1-b", "section": "§9.1.b", "name": "Distributed Custody", "text": ""}, {"id": "s9-1-c", "section": "§9.1.c", "name": "Public Accessibility", "text": ""}, {"id": "s9-1-d", "section": "§9.1.d", "name": "Cryptographic Signing", "text": ""}, {"id": "s9-1-e", "section": "§9.1.e", "name": "Technology Neutrality", "text": ""}, {"id": "s9-1-f", "section": "§9.1.f", "name": "Migration Overlap Protocol", "text": ""}, {"id": "s9-1-g", "section": "§9.1.g", "name": "NRS Self-Authentication", "text": ""}, {"id": "s9-2", "section": "§9.2", "name": "Node Operators", "text": ""}, {"id": "s9-3", "section": "§9.3", "name": "RSA Director", "text": ""}, {"id": "s9-4", "section": "§9.4", "name": "Classification Authority", "text": ""}, {"id": "s9-5-a", "section": "§9.5.a", "name": "Classification Authority", "text": ""}, {"id": "s9-5-b", "section": "§9.5.b", "name": "Classification Duration", "text": ""}, {"id": "s9-5-c", "section": "§9.5.c", "name": "Classification Registry", "text": ""}, {"id": "s9-5-d", "section": "§9.5.d", "name": "Automatic Declassification", "text": ""}, {"id": "s9-5-e", "section": "§9.5.e", "name": "Improper Classification", "text": "Classification used to conceal a constitutional violation, an illegal order, or embarrassing but non-sensitive information is constitutionally prohibited in itself. Improper classification is not an administrative error — it is a constitutional offense — it is a constitutional offense."}, {"id": "s10-1", "section": "§10.1", "name": "The Basic Needs Floor", "text": ""}, {"id": "s10-1-a", "section": "§10.1.a", "name": "Anti-Evasion Principle", "text": ""}, {"id": "s10-1-d", "section": "§10.1.d", "name": "Severe Contraction Protocol — Activation", "text": ""}, {"id": "s10-1-e", "section": "§10.1.e", "name": "Severe Contraction Protocol — Effects", "text": ""}, {"id": "s10-1-f", "section": "§10.1.f", "name": "Severe Contraction Protocol — Parliamentary Review", "text": ""}, {"id": "s10-1-g", "section": "§10.1.g", "name": "Federal Supplementation Obligation", "text": ""}, {"id": "s10-2", "section": "§10.2", "name": "Taxation Authority", "text": ""}, {"id": "s10-2-a", "section": "§10.2.a", "name": "Tax Origination and Fiscal Objection", "text": ""}, {"id": "s10-2-b", "section": "§10.2.b", "name": "Annual Budget and Continuation Spending", "text": ""}, {"id": "s10-3", "section": "§10.3", "name": "Deficit Controls", "text": ""}, {"id": "s10-3-a", "section": "§10.3.a", "name": "Inherited Deficit Transition Threshold", "text": ""}, {"id": "s10-3-b", "section": "§10.3.b", "name": "BNF and Contraction Exemptions", "text": ""}, {"id": "s10-4-a", "section": "§10.4.a", "name": "MA Director — Elected Office", "text": ""}, {"id": "s10-4-b", "section": "§10.4.b", "name": "MA Independence", "text": ""}, {"id": "s10-4-c", "section": "§10.4.c", "name": "Transparency", "text": ""}, {"id": "s10-4-d", "section": "§10.4.d", "name": "Methodology Integrity", "text": ""}, {"id": "s10-4-e", "section": "§10.4.e", "name": "Uncertifiable Inherited Fiscal Position", "text": ""}, {"id": "s10-5-a", "section": "§10.5.a", "name": "Official Benefits", "text": ""}, {"id": "s10-5-b", "section": "§10.5.b", "name": "Financial Disclosure", "text": ""}, {"id": "s10-5-c", "section": "§10.5.c", "name": "Integrity Bans", "text": ""}, {"id": "s10-5-d", "section": "§10.5.d", "name": "Anti-Ego Provision", "text": ""}, {"id": "s10-5-e", "section": "§10.5.e", "name": "Official Records Belong to the Republic", "text": ""}, {"id": "s10-5-f", "section": "§10.5.f", "name": "Official Gifts", "text": ""}, {"id": "s10-5-g", "section": "§10.5.g", "name": "Official Intellectual Property", "text": ""}, {"id": "s10-5-h", "section": "§10.5.h", "name": "Oath of Office Requirement", "text": ""}, {"id": "s10-6-a", "section": "§10.6.a", "name": "Jury Duty", "text": ""}, {"id": "s10-6-b", "section": "§10.6.b", "name": "Defense Readiness and Veterans Obligations", "text": ""}, {"id": "s10-7", "section": "§10.7", "name": "Compensation of Public Officials", "text": "The Republic relies on a volunteer military. Emergency mobilization is governed by Article XII. The Republic acknowledges a special obligation to persons who served in military or national service — distinct from the Basic Needs Floor. Veterans obligations are constitutional commitments that survive any government transition."}, {"id": "s11-1", "section": "§11.1", "name": "Optional Referendum", "text": ""}, {"id": "s11-1-a", "section": "§11.1.a", "name": "Citizen Petition Right", "text": ""}, {"id": "s11-1-b", "section": "§11.1.b", "name": "Eligibility Screen", "text": ""}, {"id": "s11-1-c", "section": "§11.1.c", "name": "Referendum Thresholds and Finality", "text": ""}, {"id": "s11-2-a", "section": "§11.2.a", "name": "Subsidiarity Principle", "text": ""}, {"id": "s11-2-b", "section": "§11.2.b", "name": "Local Government", "text": "Local governments — cities, counties, municipalities, and other subdivisions — receive constitutional recognition as the primary points of contact between citizens and government. They are entitled to reasonable fiscal capacity to carry out their constitutional functions. States may not starve local governments to achieve de facto state centralizat"}, {"id": "s12-1", "section": "§12.1", "name": "Authorized Purposes for Military Force", "text": ""}, {"id": "s12-2", "section": "§12.2", "name": "Legislative Declaration of Defense", "text": ""}, {"id": "s12-2-a", "section": "§12.2.a", "name": "Legislative Declaration of Defense", "text": ""}, {"id": "s12-2-b", "section": "§12.2.b", "name": "Five-Year Maximum", "text": ""}, {"id": "s12-2-c", "section": "§12.2.c", "name": "Successive Declaration Standard", "text": ""}, {"id": "s12-2-d", "section": "§12.2.d", "name": "Senate Armed Services Committee", "text": ""}, {"id": "s12-2-e", "section": "§12.2.e", "name": "Military Authority During Presidential Succession Vacuum", "text": ""}, {"id": "s12-3", "section": "§12.3", "name": "Intelligence Firewall", "text": ""}, {"id": "s12-4", "section": "§12.4", "name": "Military Accountability", "text": ""}, {"id": "s12-5-a", "section": "§12.5.a", "name": "Treaty Emergency Certification", "text": ""}, {"id": "s12-5-c", "section": "§12.5.c", "name": "No Blank Check", "text": "The Treaty Emergency Certification covers operational costs for the initial response and triggers parliamentary authorization for any extended engagement. Treaties cannot be blank checks for extended military commitment for extended military commitment — each sustained engagement requires parliamentary authorization regardless of what the treaty sa"}, {"id": "s13-1", "section": "§13.1", "name": "Territorial Compact", "text": ""}, {"id": "s13-2", "section": "§13.2", "name": "The Statehood Audit", "text": ""}, {"id": "s13-2-a", "section": "§13.2.a", "name": "Fiscal Integrity", "text": ""}, {"id": "s13-2-b", "section": "§13.2.b", "name": "Legal Sync", "text": ""}, {"id": "s13-2-c", "section": "§13.2.c", "name": "The Provisional Membership Period", "text": ""}, {"id": "s13-2-d", "section": "§13.2.d", "name": "Partial Territory Statehood", "text": ""}, {"id": "s13-2-e", "section": "§13.2.e", "name": "Minimum Democratic Legitimacy", "text": ""}, {"id": "s13-2-f", "section": "§13.2.f", "name": "Territorial Minimum Institutional Floor", "text": ""}, {"id": "s13-2-g", "section": "§13.2.g", "name": "Conflict-Affected State Provisional Status", "text": ""}, {"id": "s13-3", "section": "§13.3", "name": "Mandatory Devolution", "text": ""}, {"id": "s13-3-a", "section": "§13.3.a", "name": "Devolution Triggers", "text": ""}, {"id": "s13-3-b", "section": "§13.3.b", "name": "Early Warning — Years 1 and 2", "text": ""}, {"id": "s13-3-c", "section": "§13.3.c", "name": "Devolution Vote — Year 3", "text": ""}, {"id": "s13-3-d", "section": "§13.3.d", "name": "Effect of Mandatory Devolution", "text": ""}, {"id": "s13-3-e", "section": "§13.3.e", "name": "Constitutional Challenge to Devolution", "text": ""}, {"id": "s13-4", "section": "§13.4", "name": "Voluntary Devolution", "text": ""}, {"id": "s13-4-a", "section": "§13.4.a", "name": "Voluntary Devolution Vote", "text": ""}, {"id": "s13-4-b", "section": "§13.4.b", "name": "Fiscal Transparency Requirement", "text": ""}, {"id": "s13-4-c", "section": "§13.4.c", "name": "Net-Contributor Transparency", "text": ""}, {"id": "s13-4-d", "section": "§13.4.d", "name": "Effect of Voluntary Devolution", "text": ""}, {"id": "s13-4-e", "section": "§13.4.e", "name": "Negotiated Devolution Pathway", "text": ""}, {"id": "s13-6", "section": "§13.6", "name": "Voluntary Incorporation", "text": "A devolved State loses its Senate seats on the date the Devolution Motion passes. It retains House seats proportional to population. Federal law continues to apply. The State government continues as territorial administration under federal oversight. All effects are published to the NRS the moment the Motion passes."}, {"id": "s14-1", "section": "§14.1", "name": "Acknowledgment of Prior Sovereignty", "text": ""}, {"id": "s14-2", "section": "§14.2", "name": "Treaty Supremacy and Continuity", "text": ""}, {"id": "s14-3-a", "section": "§14.3.a", "name": "Free, Prior, and Informed Consent", "text": ""}, {"id": "s14-3-b", "section": "§14.3.b", "name": "Unamendable Rights Override", "text": ""}, {"id": "s14-3-c", "section": "§14.3.c", "name": "Emergency Rights Writ", "text": ""}, {"id": "s14-3-d", "section": "§14.3.d", "name": "Internal Enforcement Support", "text": ""}, {"id": "s14-3-e", "section": "§14.3.e", "name": "Inspectorate Jurisdiction Limit", "text": ""}, {"id": "s14-4-a", "section": "§14.4.a", "name": "Eminent Domain Prohibition", "text": ""}, {"id": "s14-4-b", "section": "§14.4.b", "name": "Conservation Trust", "text": ""}, {"id": "s14-4-c", "section": "§14.4.c", "name": "National Record System", "text": ""}, {"id": "s14-5-a", "section": "§14.5.a", "name": "Article I Rights", "text": ""}, {"id": "s14-5-b", "section": "§14.5.b", "name": "Dual Citizenship", "text": ""}, {"id": "s14-5-c", "section": "§14.5.c", "name": "National Voting System — Voluntary Connection", "text": ""}, {"id": "s14-5-d", "section": "§14.5.d", "name": "Pre-Existing Sovereignty Pathway", "text": ""}, {"id": "s14-6", "section": "§14.6", "name": "Indigenous Nation Status Elections", "text": "All treaties entered into by predecessor governments with indigenous nations are binding obligations of the Republic. Treaty rights cannot be diminished by legislation — they must be honored, renegotiated with consent, or formally superseded through the FPIC framework."}, {"id": "s15-1", "section": "§15.1", "name": "Two Amendment Paths", "text": ""}, {"id": "s15-1-a", "section": "§15.1.a", "name": "Parliamentary Path", "text": ""}, {"id": "s15-1-b", "section": "§15.1.b", "name": "Parliamentary and Popular Path", "text": ""}, {"id": "s15-1-c", "section": "§15.1.c", "name": "Citizen-Led Path", "text": ""}, {"id": "s15-2", "section": "§15.2", "name": "No Executive Veto Over Amendments", "text": ""}, {"id": "s15-2-a", "section": "§15.2.a", "name": "No Executive Veto", "text": ""}, {"id": "s15-3-a", "section": "§15.3.a", "name": "Permanently Unamendable Provisions", "text": ""}, {"id": "s15-4-a", "section": "§15.4.a", "name": "Territorial Integrity", "text": ""}, {"id": "s15-4-b", "section": "§15.4.b", "name": "Advisory Referenda", "text": ""}, {"id": "s15-5", "section": "§15.5", "name": "Independence Transition Framework", "text": ""}, {"id": "s15-5-a", "section": "§15.5.a", "name": "Framework Agreement Requirement", "text": ""}, {"id": "s15-5-b", "section": "§15.5.b", "name": "Transition Period — 24 to 60 Months", "text": ""}, {"id": "s15-5-c", "section": "§15.5.c", "name": "Basic Needs Floor Transition", "text": ""}, {"id": "s15-5-d", "section": "§15.5.d", "name": "Executive Authority During Transition", "text": ""}, {"id": "s15-5-e", "section": "§15.5.e", "name": "Simultaneous Independence Sequencing", "text": ""}, {"id": "s15-6", "section": "§15.6", "name": "Supremacy of This Constitution", "text": ""}, {"id": "s15-6-b", "section": "§15.6.b", "name": "Federal-State Statutory Hierarchy", "text": "Despite §10.1 applying to Republic Inhabitants, the Republic's obligations to the departing territory during the transition period must be specified in the framework agreement. Independence does not end Republic obligations to former Territory residents immediately. The transition period is a period of defined ongoing obligation."}, {"id": "s16-116-2", "section": "§16.1–16.2", "name": "Electoral Commission", "text": "The Electoral Commission is five members, all elected by citizens at staggered intervals. No member may have held elected office or party membership within ten years of appointment — the independence requirement is structural, not aspirational. The Commission administers all national elections, certifies candidate registers, and is the final author"}, {"id": "s16-2", "section": "§16.2", "name": "Electoral Commission Qualifications", "text": "Electoral Commission members must meet three independently verified requirements: at least 15 years of professional expertise in elections, technology, or public administration; no current or recent partisan affiliation; and passage of the Constitutional Logic Test. The qualifications are substantive — the EC requires genuine expertise."}, {"id": "s16-2-a", "section": "§16.2.a", "name": "Electoral Commission Removal", "text": "For-cause only — no no-cause removal. EC administers all elections; no-cause removal would be a vector for electoral manipulation. Process: JI documents finding → State Designee Panel substantiates → 14-day SC appeal window expires (or SC upholds on appeal) → member suspended from all EC duties. The 180-day election proximity restriction in §16.5.c"}, {"id": "s16-3", "section": "§16.3", "name": "NVS Properties", "text": "Three constitutionally required properties of the National Voting System: ballot secrecy (technically impossible to link any vote to any voter), public auditability (aggregate results mathematically verifiable by anyone with NRS access), and resilience (capable of operating in degraded conditions without compromising either secrecy or auditability)"}, {"id": "s16-3-a", "section": "§16.3.a", "name": "Ballot Secrecy", "text": "No person or institution — including Electoral Commission members — may identify how any individual citizen voted. Ballot secrecy is constitutionally absolute. The NVS must make it technically impossible to link any vote to any voter, even in post-election audits."}, {"id": "s16-3-b", "section": "§16.3.b", "name": "Public Auditability", "text": "Every vote cast through the NVS must be individually verifiable by the voter who cast it, without revealing that voter's identity to any other party. The NVS must produce an audit trail that allows independent verification of aggregate results without individual identification. Both requirements must be simultaneously satisfied."}, {"id": "s16-3-c", "section": "§16.3.c", "name": "Resilience and Privacy", "text": "The NVS must operate in degraded conditions without compromising ballot secrecy or auditability. No information generated by the NVS — including voter participation records — may be shared with any government body, law enforcement, or foreign entity for any purpose other than administering the relevant election or referendum. Voter participation da"}, {"id": "s16-4-a", "section": "§16.4.a", "name": "The Citizen Voting Credential", "text": "The Citizen Voting Credential is issued and managed by the Electoral Commission. The system stores only cryptographic identifiers — not names, biometric data, or personal information — ensuring the link between a citizen and their credential cannot be used to..."}, {"id": "s16-4-b", "section": "§16.4.b", "name": "Remote Voting", "text": "Legislature may by statute authorize authenticated remote voting through the NVS. Remote voting must meet the same cryptographic and auditability standards as in-person NVS voting. No remote voting system may reduce ballot secrecy or auditability below the in-person standard."}, {"id": "s16-4-c", "section": "§16.4.c", "name": "State Voting Method Flexibility", "text": "States may implement early voting periods, mail-in ballot options, and alternative participation methods, provided all methods connect to the NVS and meet its cryptographic and auditability standards. States may not reduce NVS access or capacity as a condition of offering alternative methods. Added v143."}, {"id": "s16-4-d", "section": "§16.4.d", "name": "Federal Ballot Information", "text": "Before each federal election window opens, the Electoral Commission delivers to every eligible citizen: the list of federal races on their ballot, the NVS access procedures, and the certification timeline. Delivery must reach every eligible citizen through at least two distinct channels. Added v143."}, {"id": "s16-4-e", "section": "§16.4.e", "name": "State Ballot Information on Request", "text": "At a state's request, EC may extend ballot information delivery to cover state and local races. State bears cost. EC cannot refuse except on operational capacity grounds. Entirely voluntary. New in v143."}, {"id": "s16-5-a", "section": "§16.5.a", "name": "Campaign Funding", "text": "Campaigns for Electoral Commission seats are publicly funded in full. No private money may be spent on EC campaigns. The EC administers elections for all other offices — it cannot itself be captured by the interests that it would regulate in other campaigns."}, {"id": "s16-5-b", "section": "§16.5.b", "name": "JI Oversight", "text": "The Judicial Inspectorate audits the Electoral Commission annually. The JI is the appropriate Inspectorate for EC oversight — it audits judicial independence, and electoral integrity has similar structural properties. JI audit findings on the EC are published to the NRS and presented to both chambers."}, {"id": "s16-5-c", "section": "§16.5.c", "name": "Removal", "text": "For-cause only, 2/3 both chambers simultaneously, preceded by State Designee Panel verification. 180-day election proximity rule: any removal vote within 180 days of a major national election is automatically suspended pending SC review within 48 hours. Critically: the proximity restriction applies to the removal vote only — Panel-triggered suspens"}, {"id": "s16-5-d", "section": "§16.5.d", "name": "Mid-Term Vacancy", "text": "Where any Electoral Commission seat becomes vacant mid-term, a special election is held within 90 days through the NVS. The replacement serves a full new non-renewable 6-year term from certification — not the remainder of the vacated term. The Commission operates under its active-membership threshold during the vacancy period."}, {"id": "s16-6", "section": "§16.6", "name": "Electoral Commission Technical Deadlock", "text": "Legislature must establish by statute a procedure for the EC to adopt temporary technical measures in imminent security threats or system failures, bypassing the normal 3/5 decision threshold. The emergency power is narrowly constrained — it cannot change electoral rules, timelines, or candidate eligibility. A system-integrity tool only."}, {"id": "s16-7", "section": "§16.7", "name": "Day Zero Voting System Transition", "text": "Legislature must establish by statute the transition from any predecessor voting infrastructure to the constitutionally required NVS. The statute must ensure continuity of democratic participation — no gap between the predecessor system going offline and the NVS coming online. The ratification vote itself was conducted on the NVS (§19.1)."}, {"id": "s17-1", "section": "§17.1", "name": "The Use Doctrine", "text": "Federal government holds no territorial sovereignty within any State or Territory. All federal property rights are functional use rights — operational control over a designated footprint for the duration of the stated function. Use rights do not constitute ownership, do not transfer sovereignty from the host State, and do not survive the terminatio"}, {"id": "s17-2", "section": "§17.2", "name": "Seat of Government", "text": "The Republic does not have a permanent capital city with territorial sovereignty. The Seat of Government is hosted by a consenting State — the host retaining sovereignty outside the specific federal footprint. The Republic exercises functional authority, not territorial sovereignty, within the footprint. This design prevents the accumulation of fed"}, {"id": "s17-2-a", "section": "§17.2.a", "name": "Host State Consent", "text": "The host State consents to hosting the Seat of Government by a majority vote of its legislature, recorded on the NRS. Consent is explicit, documented, and revocable. A State cannot be involuntarily assigned as the host."}, {"id": "s17-2-b", "section": "§17.2.b", "name": "Federal Control Within the Footprint", "text": "Within the specific registered footprint, the federal government has exclusive operational control. Host State may not tax federal operations, interfere with federal functions, or apply State law to federal employees acting in official capacity on federal grounds. The footprint is fixed — expansion requires a new Host State Agreement. Federal contr"}, {"id": "s17-2-c", "section": "§17.2.c", "name": "Resident Rights", "text": "No State may be involuntarily designated as the permanent seat of government. A State may withdraw consent to host the seat of government by a 2/3 vote of its legislature, subject to a statutory transition period during which the Republic must identify a new host or trigger the provisional host designation under §17.2.e."}, {"id": "s17-2-d", "section": "§17.2.d", "name": "Reversion on Relocation", "text": "If the seat of government relocates, the prior host State recovers full sovereignty over all previously designated grounds upon completion of the statutory transition period. Individual facilities remaining in active operational use may be retained as Operational Use Rights by mutual agreement. All improvements revert to the host State unless other"}, {"id": "s17-2-e", "section": "§17.2.e", "name": "Provisional Seat — No Voluntary Host", "text": "If no State consents to host the seat within 24 months of ratification — or within 24 months of a host State withdrawing consent — the Legislature may by 2/3 vote designate any State as provisional host. The provisional designation holds until a State volunteers; the designated State may not be involuntarily permanent."}, {"id": "s17-3-a", "section": "§17.3.a", "name": "Registration", "text": "Every federal operational use right must be registered on the NRS with precise geographic boundaries, authorized purpose, and termination conditions. There are no unregistered federal land claims. Federal property rights are explicit, bounded, and auditable."}, {"id": "s17-3-b", "section": "§17.3.b", "name": "Termination and Reversion", "text": "When a federal function ends, the Operational Use Right terminates automatically. The federal government must publish notice of termination to the NRS within 30 days. The land and all improvements revert to the host State automatically unless the federal government and host State negotiate a retention agreement within the statutory settlement windo"}, {"id": "s17-3-c", "section": "§17.3.c", "name": "Improvements — Negotiated Settlement", "text": "All improvements on federal Operational Use Rights default to reverting to the host State with the land. The federal government and host State may negotiate a different arrangement within the statutory reversion window. No agreement means automatic reversion at no cost. The burden is on the federal government to negotiate retention — not on the Sta"}, {"id": "s17-3-d", "section": "§17.3.d", "name": "Disputes", "text": "Disputes over use right boundaries, termination, or improvement valuation go to the SC on an expedited track. Neither party may occupy or alter disputed land during pending resolution. The expedited track ensures federal operational continuity — resolution must happen fast enough to maintain the relevant federal function."}, {"id": "s17-3-e", "section": "§17.3.e", "name": "Independence Transition", "text": "Where a State achieves independence through §15.4 and §15.5, automatic reversion under §17.3.b does not immediately apply to Operational Use Rights within the departing territory. Use rights continue under the terms of the framework agreement and independence treaty negotiated under §15.5.a. This prevents independence from instantly stranding criti"}, {"id": "s17-4", "section": "§17.4", "name": "The National Trust", "text": "The National Trust holds all federal land not conveyed by statute to States, indigenous compact territories, or private parties. Land disposal requires statute — the executive cannot convey or encumber public land unilaterally, preventing privatization by executive discretion. The National Trust Administrator is independently confirmed under the §2"}, {"id": "s17-4-a", "section": "§17.4.a", "name": "Trust Nature", "text": "National Trust lands are designated as permanent heritage, ecological, or public recreation resources. Trust designation requires a 2/3 vote of both chambers with host State consent. Trust lands are not subject to Operational Use Right termination. The stewardship obligation (§17.4.b) applies from the date of designation."}, {"id": "s17-4-b", "section": "§17.4.b", "name": "Stewardship Obligation", "text": "The federal government has an active, enforceable obligation to maintain ecological integrity and public accessibility of National Trust lands. EI monitors stewardship compliance annually, cross-referenced with §1.22 (Right to a Healthy Environment). Failure triggers a mandatory remediation plan reported to the NRS. The Trust carries active obligat"}, {"id": "s17-4-c", "section": "§17.4.c", "name": "Co-Management", "text": "States and indigenous nations may enter co-management agreements with the Domestic Affairs Council for National Trust lands within their borders or ancestral territories. Co-management does not transfer Trust ownership or alter the constitutional Trust status. Indigenous nations' participation reflects the §14.3 government-to-government relationshi"}, {"id": "s17-4-d", "section": "§17.4.d", "name": "Reclassification Threshold", "text": "Land may be removed from National Trust designation only by a 2/3 vote of both chambers with host State consent, followed by SC review within 60 days. The SC reviews whether the removal complies with any applicable international obligations. Removal is permanent — land removed from Trust does not automatically revert to Trust status."}, {"id": "s17-4-e", "section": "§17.4.e", "name": "International Sites", "text": "National Trust lands recognized under international conservation agreements require a 2/3 Senate vote to withdraw from the relevant international obligation before the national removal process begins. The Republic cannot quietly delist internationally recognized sites without formal democratic action."}, {"id": "s17-4-f", "section": "§17.4.f", "name": "Admission of New Trust Lands", "text": "Land may be designated National Trust by a 2/3 vote of both chambers with host State consent (land in Territories: 2/3 vote alone). No executive action may designate Trust lands — designation is a legislative act. Prevents executive land grabs under Trust designation and executive stripping of Trust status."}, {"id": "s17-4-g", "section": "§17.4.g", "name": "National Trust Administrator", "text": "The NTA is a statutory independent officer under §3.7 — the legislature creates the office by statute and calibrates its independence, term, and removal grounds through the enabling statute. The constitutional protections that matter for the Trust are in §17.4.a–f: the trust nature, the 65% referendum threshold for reclassification, the stewardship"}, {"id": "s17-5", "section": "§17.5", "name": "Federal Property in Territories", "text": "Federal use rights in Territories follow the same framework as in States — Operational Use Rights (§17.3) and National Trust (§17.4) — without requiring host State legislative consent (Territories have no State legislature). The Territory's representative body and the LI are consulted. Same constitutional principles; consent mechanism adapts to the"}, {"id": "s18-1-a", "section": "§18.1.a", "name": "Financial Contributions as Electoral Acts", "text": ""}, {"id": "s18-1-b", "section": "§18.1.b", "name": "Natural Persons Only", "text": ""}, {"id": "s18-1-c", "section": "§18.1.c", "name": "Voter-Donor Parity", "text": ""}, {"id": "s18-1-d", "section": "§18.1.d", "name": "Full Disclosure", "text": ""}, {"id": "s18-2-a", "section": "§18.2.a", "name": "Qualification Threshold", "text": ""}, {"id": "s18-2-b", "section": "§18.2.b", "name": "Adequate Allocation", "text": ""}, {"id": "s18-2-c", "section": "§18.2.c", "name": "Optional Participation", "text": ""}, {"id": "s18-2-d", "section": "§18.2.d", "name": "EC Administration", "text": ""}, {"id": "s18-3-a", "section": "§18.3.a", "name": "Separation from the Voting System", "text": ""}, {"id": "s18-3-b", "section": "§18.3.b", "name": "Registry Contents", "text": ""}, {"id": "s18-3-c", "section": "§18.3.c", "name": "Aggregate Attribution", "text": ""}, {"id": "s18-3-d", "section": "§18.3.d", "name": "Administration", "text": "Financial contributions to electoral campaigns are not constitutionally protected speech under §1.4, and are not protected as associational activity under §1.7. The regulation of electoral finance is a matter of democratic integrity explicitly reserved from both speech and associational protection. One of the most direct rejections of Citizens Unit"}, {"id": "s19-1", "section": "§19.1", "name": "The Activation Threshold", "text": "Three subsections after v145 restructuring: activation threshold (§19.1.a), institutional accommodation for existing legal structures (§19.1.b), and multi-founder formation for sovereign nations pooling sovereignty (§19.1.c). Previously a single wall-of-text paragraph — restructuring makes §19.1 readable without changing any substantive content."}, {"id": "s19-1-a", "section": "§19.1.a", "name": "Activation Threshold", "text": "Activated upon: (1) interim EC certification that the NVS is operational and meets §16.3; and (2) a national ratification vote achieving 60% affirmative support with at least 50% participation. The NVS certification requirement ensures the system that conducts the ratification vote meets constitutional standards before the vote itself."}, {"id": "s19-1-b", "section": "§19.1.b", "name": "Institutional Accommodation", "text": "Where the ratifying polity maintains existing institutions overlapping with constitutional mechanisms, the Legislature must by statute within two years of Phase 4 define their relationship with the constitutional framework. Non-diminishment: accommodation statutes may not reduce legal standing of pre-existing governance structures below their pre-P"}, {"id": "s19-1-c", "section": "§19.1.c", "name": "Multi-Founder Formation", "text": "Where multiple sovereign nations simultaneously pool sovereignty through a treaty of union, transition provisions adapt: joint Phase 0/1 certification, consolidated debt assumption, combined Day Zero NRS publication of all founding sovereigns' records, and proportional obligation assumption per treaty terms."}, {"id": "s19-2", "section": "§19.2", "name": "Day Zero", "text": "Day Zero is the date the ratification threshold is certified as achieved by the interim EC. Upon ratification: all laws conflicting with the Individual Sovereignty Floor are immediately null and void; all public assets transfer to the NRS; the 24-month Transition Window begins. The Republic exists the moment the EC certifies the threshold."}, {"id": "s19-3", "section": "§19.3", "name": "The Four-Phase Transition", "text": "24-month, four-phase process. Seven provisions: Phase 0 pre-ratification preparation (§19.3.a), Phase 1 emergency stabilisation Days 1-90 (§19.3.b), Phase 2 institutional construction Days 91-270 (§19.3.c), Phase 3 first elections Days 271-450 (§19.3.d), Phase 4 full operation (§19.3.e), provisional NRS authority (§19.3.f), and phase extension mech"}, {"id": "s19-3-a", "section": "§19.3.a", "name": "Phase 0 — Pre-Ratification Preparation", "text": "Phase 0 is the pre-ratification preparation period. The interim Electoral Commission is constituted, the National Voting System is certified operational, and the joint Inspectorate panel is formed — all before any ratification vote occurs. The Republic's constitutional infrastructure must exist before it can be activated."}, {"id": "s19-3-b", "section": "§19.3.b", "name": "Phase 1 — Emergency Stabilization (Days 1–90)", "text": "Existing government officials serve as caretakers under §19.4. The joint Inspectorate panel assumes oversight. The NRS begins recording all government acts. Priority functions: Basic Needs Floor delivery continuity, public safety, and essential services. No new permanent legislation. This phase is explicitly temporary — its only mandate is stabilit"}, {"id": "s19-3-c", "section": "§19.3.c", "name": "Phase 2 — Institutional Construction (Days 91–270)", "text": "Phase 2 (Days 91–270) is Institutional Construction. Statehood Audits are conducted for all entering territories. Inspectorates are formally constituted. The Candidate Register for MA board members and the RSA Director is assembled. Electoral Commission is certified as operational. The National Voting System is fully deployed for citizen registrati"}, {"id": "s19-3-d", "section": "§19.3.d", "name": "Phase 3 — First Elections (Days 271–450)", "text": "Phase 3 (Days 271-450) is First Elections. The first National Election Day. Supreme Court justices elected through the open-candidacy judicial selection process. Electoral Commission inaugural elections. Phase 3 ends when the first the Legislature is sworn in and the first executives take office — the moment at which the Republic's constitutional d"}, {"id": "s19-3-e", "section": "§19.3.e", "name": "Phase 4 — Full Constitutional Operation", "text": "Phase 4 is Full Constitutional Operation — beginning the day the first Legislature convenes and the first executives take the constitutional oath. From Phase 4, all constitutional provisions are fully operative. The 18-month Transition Window concludes at the end of Phase 4."}, {"id": "s19-4", "section": "§19.4", "name": "Caretaker Status", "text": "All existing government officials serve as caretakers during the Transition Window — restricted to maintaining existing services only. No new permanent legislation. Transition supervised by joint Inspectorate panel: one representative per Inspectorate, appointed by their respective IGs. The panel dissolves automatically at the Transition Window's c"}, {"id": "s19-5", "section": "§19.5", "name": "Pre-Constitutional Classified Documents", "text": "Legislature must establish a Classification Review Commission within 90 days of Phase 4 activation. Commission applies §9.5 criteria to predecessor classified material: legitimately classified material enters the §9.5 duration framework from Day Zero; improperly classified material (concealing violations or policy decisions) is immediately declassi"}, {"id": "s19-6", "section": "§19.6", "name": "Pre-Existing Obligations", "text": "The Republic assumes the public debt obligations of its predecessor government as a constitutional matter, not a discretionary choice. This prevents the Republic from being born into sovereign default by simply denying predecessor debts — a move that would destabilize the fiscal foundations of the transition period. The assumption covers public deb"}, {"id": "s19-6-a", "section": "§19.6.a", "name": "Debt Assumption", "text": "The Republic assumes all legally recognized debts of the prior government. The Republic does not inherit a clean slate — it inherits what was borrowed. Selective repudiation of prior obligations is not available as a founding act."}, {"id": "s19-6-b", "section": "§19.6.b", "name": "Active Military Operations", "text": "Active military operations of the prior government continue under existing authorization until the §12.2 Tier framework can apply. The President, once inaugurated, must certify each active operation under the appropriate Tier within 14 days or begin orderly cessation. Operations not certified within 60 days of inauguration cease unless the Legislat"}, {"id": "s19-6-c", "section": "§19.6.c", "name": "Social Insurance Programs", "text": "Existing social insurance programs — retirement pensions, disability benefits, health coverage — of the prior government continue uninterrupted during the Transition Window. The Republic does not create a gap in social protection as part of its founding."}, {"id": "s19-6-d", "section": "§19.6.d", "name": "Veterans and National Service Obligations", "text": "The Republic inherits and honors all benefit obligations to persons who served in military or national service roles under the prior government. These are existing contractual commitments of the sovereign that survive transition as continuity-of-state. Legislature must pass a Veterans and National Service Benefits Act within the first budget cycle "}, {"id": "s19-6-e", "section": "§19.6.e", "name": "Constitutional Claims Court", "text": "The immediate nullification of laws conflicting with the Individual Sovereignty Floor creates constitutional disputes that existing courts may not have capacity to absorb. The Legislature must by statute establish an interim Constitutional Claims Court within Phase 2, with jurisdiction over all Article I claims arising from Day Zero nullification."}, {"id": "s19-6-f", "section": "§19.6.f", "name": "Legal Continuity", "text": "The Federated Republic is the legal continuation of the prior government as a matter of international law. All international obligations, financial commitments, treaty relationships, and contractual obligations of the prior government as of Day Zero are assumed by the Republic as its successor sovereign. This ensures that the Republic is not born i"}, {"id": "s19-7-a", "section": "§19.7.a", "name": "Transition-Period Territorial Elections", "text": "Territories or subdivisions meeting the §13.2 Competency Baseline by Phase 2 end may petition to enter as State or Territory. Those failing the Baseline enter as Territory under §13.1 and may begin the Statehood Audit immediately. Any territory may choose Territory status by simple legislative vote regardless of whether it meets the Statehood Basel"}, {"id": "s19-7-b", "section": "§19.7.b", "name": "Subdivision Elections", "text": "Prior government states or territories may voluntarily subdivide during the Transition Window by vote of their existing legislative body. New subdivisions are treated as separate petitioning entities for §19.7.a purposes. Legislature must establish by statute the subdivision recognition process."}, {"id": "s19-7-c", "section": "§19.7.c", "name": "Phase 2 Statehood Audit Failures", "text": "Where a state fails the Phase 2 Statehood Audit, it enters as a Territory under §13.1 rather than a State. Its population retains all Article I rights. Territory residents from failed-audit states participate in first House elections proportionally. Audit failure does not disenfranchise the population."}, {"id": "s19-7-d", "section": "§19.7.d", "name": "Pre-Existing Territories and the District", "text": "All prior government territories that have not achieved statehood by Day Zero enter as Territories from Phase 4 activation — without undergoing Phase 2 Statehood Audits, beginning the standard §13.2 Statehood Audit process after Phase 4. Any capital district or special administrative region that was neither a state nor standard territory is assigne"}, {"id": "s19-8", "section": "§19.8", "name": "Transition Candidate Registers", "text": "The joint Inspectorate panel assembles the initial Candidate Registers for all constitutionally established positions before Phase 3 elections can occur. Without populated registers, the elections cannot proceed — the Registers are a constitutional prerequisite for the democratic machinery to activate. The panel's role here is transitional: it perf"}, {"id": "s19-8-a", "section": "§19.8.a", "name": "Initial Register Assembly", "text": "During Phase 2, the joint Inspectorate panel assembles an initial Candidate Register for the MA board members and RSA Director. Panel receives disclosure records, reviews factual accuracy, applies constitutional eligibility criteria, and publishes with recommendations to NRS. May draw on prior government, international, and diaspora expertise where"}, {"id": "s19-8-b", "section": "§19.8.b", "name": "Interim Functions and First Nomination", "text": "The joint Inspectorate panel performs interim MA fiscal certification functions from Phase 4 activation until the first MA Director takes office following the Phase 3 election. These interim certifications carry full constitutional weight. The first PM must nominate MA board members within 90 days of Phase 4 activation and an RSA Director within 18"}, {"id": "s19-9", "section": "§19.9", "name": "Transitional Accountability Mechanism", "text": "Where a ratifying polity's predecessor government has documented constitutional violations — systematic rights abuses, documented atrocities — the Republic may establish a Transitional Accountability Mechanism by statute. The TAM is time-limited, non-criminal (it cannot impose criminal sentences), and subject to NRS publication. It is the the const"}, {"id": "s19-9-a", "section": "§19.9.a", "name": "TAM Establishment and Scope", "text": "The Transitional Accountability Mechanism investigates, documents, and recommends remedies for serious violations committed by predecessor government entities during the period before ratification. Its jurisdiction is bounded to predecessor-era conduct — it does not adjudicate Republic-era acts, which fall to ordinary courts. Findings are published"}, {"id": "s19-9-b", "section": "§19.9.b", "name": "TAM Amendment and Successor Bar", "text": "The establishing statute and any amendments to it require the same 2/3 majority of both chambers as the original statute. No amendment may expand the Mechanism's subject matter scope beyond the scope defined in the establishing statute."}, {"id": "s19-9-c", "section": "§19.9.c", "name": "TAM Jurisdiction and Publication Limits", "text": "The Mechanism may not exercise criminal jurisdiction — that remains with the courts. The Mechanism may not issue orders whose practical effect is equivalent to criminal punishment, including mandatory prosecution referrals with binding recommendations, civil..."}, {"id": "s19-9-d", "section": "§19.9.d", "name": "TAM Sunset and Rationale", "text": "At sunset the Mechanism dissolves; its NRS record is permanent. The Legislature may not extend the Mechanism beyond its statutory sunset without a fresh 2/3 supermajority in both chambers; extension is not a renewal and does not reset the ten-year successor bar..."}, {"id": "s20-1", "section": "§20.1", "name": "Associated Community Status", "text": "Exclusively for sovereign entities — not a form of State or Territory status, not transitional, not incorporation. Available to nations that have completed the independence process under §15.4-15.5, to independent nations outside the Republic seeking a defined relationship, or to nations recognised as pre-existing sovereigns under Article XIV. A di"}, {"id": "s20-2", "section": "§20.2", "name": "Compact Terms and Equal Sovereignty", "text": "Equal parties; neither constitutionally superior. Observing delegates attend House and Senate proceedings relevant to the compact — speaking rights, no vote, no quorum or threshold effect. The Republic may not impose its constitutional governance architecture on an Associated Community as a condition of the compact relationship. Minimum democratic "}, {"id": "s20-3", "section": "§20.3", "name": "Compact Conditions and Compliance", "text": "No compact may be entered or ratified with any entity whose governance practices include, authorise, or systematically permit torture, slavery, or the denial of habeas corpus to any person within its jurisdiction. The Judicial Inspectorate certifies..."}, {"id": "s20-4", "section": "§20.4", "name": "Sovereign Mobility", "text": "The Associated Community may at any time, by its own democratic or traditional governance process, elect to terminate the compact and proceed as a fully independent sovereign nation. No Republic consent is required for compact termination by the Associated..."}, {"id": "s20-5", "section": "§20.5", "name": "Reciprocal Obligations and Review", "text": "The compact must specify with particularity the reciprocal obligations of both parties and the review mechanism. The Associated Community holds obligations to the Republic as well as rights from it. Review must be scheduled at regular intervals defined in the compact; either party may request a review outside the schedule by providing written notic"}];